   289	    /// Get a random byte array which has [`u8::MIN`] at each index and is
   290	    /// between the min and max bounds (which are assumed to also be arrays
   291	    /// of [`u8::MIN`]).
   292	    fn minvalue_bytes(
   293	        rng: &mut TestRng,
   294	        min_bound: Bound<usize>,
   295	        max_bound: Bound<usize>,
   296	    ) -> Bytes {
   297	        let min_len = match min_bound {
   298	            Unbounded => 0,
   299	            Included(len) => len,
   300	            Excluded(len) => len + 1,
   301	        };
   302	
   303	        let max_len = match max_bound {
   304	            Unbounded => min_len + 10,
   305	            Included(len) => len,
   306	            Excluded(len) => len - 1,
   307	        };
   308	
   309	        let len = rng.random_range(min_len..=max_len);
   310	        Bytes::from(vec![u8::MIN; len])
   311	    }
