   320	    fn padded_bytes(b: &[u8], value: u8, len: usize) -> Bytes {
   321	        let mut padded = BytesMut::from(b);
   322	        while padded.len() < len {
   323	            padded.put_u8(value);
   324	        }
   325	        padded.freeze()
   326	    }
