   328	    fn inclusive_end_bound(range: &BytesRange, len: usize) -> Bytes {
   329	        match range.end_bound() {
   330	            Unbounded => padded_bytes(&Bytes::new(), u8::MAX, len),
   331	            Included(b) | Excluded(b) => {
   332	                let b = padded_bytes(b, u8::MIN, len);
   333	                decrement_lex(&b)
   334	            }
   335	        }
   336	    }
