   338	    fn inclusive_start_bound(range: &BytesRange, len: usize) -> Bytes {
   339	        match range.start_bound() {
   340	            Unbounded => padded_bytes(&Bytes::new(), u8::MIN, len),
   341	            Included(b) => padded_bytes(b, u8::MIN, len),
   342	            Excluded(b) => {
   343	                let padded = padded_bytes(b, u8::MIN, len);
   344	                if b.len() < len {
