   357	    pub(crate) fn bytes_in_range(rng: &mut TestRng, range: &BytesRange) -> Bytes {
   358	        assert!(
   359	            range.non_empty(),
   360	            "Cannot choose an arbitrary value from an empty range"
   361	        );
   362	
   363	        if let Some(end) = test_utils::bound_as_option(range.end_bound()) {
   364	            if !can_decrement_without_truncation(end) {
   365	                let min_len = match range.start_bound() {
   366	                    // If start bound is unbounded, minvalue_bytes uses 0 as the length,
   367	                    // and random_range(0 ..) is inclusive. This can lead to an empty length
   368	                    // result, which will trigger a failure in the assertion below (is_empty).
   369	                    // Prevent this by using Excluded(0) as the min len so we get a non-empty
   370	                    // result no matter what.
   371	                    Unbounded => Excluded(0),
   372	                    Included(b) => Included(b.len()),
   373	                    Excluded(b) => Excluded(b.len()),
   374	                };
   375	                let max_len = range.end_bound().map(|b| b.len());
   376	                let result = minvalue_bytes(rng, min_len, max_len);
   377	                assert!(
   378	                    !result.is_empty(),
   379	                    "calculated empty bytes for range {range:?}"
   380	                );
   381	                return result;
   382	            } else if range.start_bound() == Included(end) {
   383	                return end.clone();
   384	            } else {
   385	                let start = test_utils::bound_as_option(range.start_bound())
   386	                    .cloned()
   387	                    .unwrap_or_default();
   388	                if bytes_range::is_prefix_increment(&start, end) {
   389	                    let mut tmp = Vec::new();
   390	                    if matches!(range.start_bound(), Included(_) | Unbounded) {
   391	                        tmp.push(start);
   392	                    }
   393	                    if matches!(range.end_bound(), Included(_)) {
   394	                        tmp.push(end.clone());
   395	                    }
   396	                    tmp.shuffle(rng);
   397	                    return tmp.pop().unwrap();
   398	                }
   399	            }
   400	        }
   401	
   402	        let len = max(bound_len(range.start_bound()), bound_len(range.end_bound())) + 3;
   403	        let start_bound = inclusive_start_bound(range, len);
   404	        let end_bound = inclusive_end_bound(range, len);
   405	        bytes_between(rng, &start_bound, &end_bound)
   406	    }
